import type { Account } from './account-model';
import type { Opportunity } from './opportunity-model';

export const SignalSeveritykeyToLabel = {
  'Severitykey0': 'critical',
  'Severitykey1': 'warning',
  'Severitykey2': 'info',
  'Severitykey3': 'positive'
} as const;
export type SignalSeveritykey = keyof typeof SignalSeveritykeyToLabel;

export interface Signal {
  /**
   * @displayName Signal
   * @description Unique system identifier - GUID generated by system
   * @uiConstraints NEVER create input fields for this ID
   */
  id: string;
  /**
   * @displayName Signal Type
   * @description Human-readable record identifier
   * @validationRule Required for create/update operations
   */
  signaltype: string;
  /**
   * @displayName Account
   */
  account?: Pick<Account, 'id' | 'name1'>;
  /**
   * @displayName Description
   */
  description?: string;
  /**
   * @displayName Detected On
   * @validationRule Required for create/update operations
   */
  detectedon: string;
  /**
   * @displayName Is Active
   */
  isactive?: boolean;
  /**
   * @displayName Opportunity
   */
  opportunity?: Pick<Opportunity, 'id' | 'name1'>;
  /**
   * @displayName Owner ID
   * @validationRule Required for create/update operations
   */
  ownerid: string;
  /**
   * @displayName Related Data JSON
   */
  relateddatajson?: string;
  /**
   * @displayName Severity
   */
  severityKey?: SignalSeveritykey;
  /**
   * @displayName Title
   * @validationRule Required for create/update operations
   */
  title: string;
}

export const _Signal = 'Signal' as const;